class ShortUrlStore:
    def __init__(self):
        self._urls = {}

    def get(self, short_url: str) -> Optional[dict]:
        return self._urls.get(short_url)

    def exists(self, short_url: str) -> bool:
        return short_url in self._urls

    def create(self, short_url: str, original_url: str, alias: Optional[str] = None):
        if alias is not None and alias in self._urls:
            raise HTTPException(status_code=status.HTTP_409 status_code, detail="Custom alias already exists")

        if alias is not None:
            self._urls[alias] = {"short": short_url, "original": original_url, "metadata": {}}
        else:
            self._urls[short_url] = {"short": short_url, "original": original_url, "metadata": {}}

    def delete(self, short_url: str):
        if not self.exists(short_url):
            raise HTTPException(status_code=status.HTTP_404 status_code, detail="Short URL not found")
        del self._urls[short_url]

class ShortUrlRequest(BaseModel):
    url: str
    alias: Optional[str] = None
    custom_metadata: Optional[dict] = None

class ShortUrlMetadata(BaseModel):
    short: str
    original: str
    timestamp: str
    referrer: Optional[str] = None
    user_agent: Optional[str] = None
    click_count: int = 0

class ShortUrlService:
