            request_data=ShortUrlRequest(
                url=short_url,
                alias=alias,
                custom_metadata={},
            )
        )
        if alias is not None and alias in self._store:
            raise HTTPException(status_code=status.HTTP_409 status_code, detail="Custom alias already exists")

        if alias is not None:
            shortened_url = alias
        else:
            shortened_url = short_url

        metadata = request.validated_data.custom_metadata or {}
        metadata["timestamp"] = datetime.now().isoformat()
        if request.validated_data.referrer:
            metadata["referrer"] = request.validated_data.referrer
        if request.validated_data.user_agent:
            metadata["user_agent"] = request.validated_data.user_agent

        self._store.create(shortened_url, original_url, alias)
        return {
            "short": shortened_url,
            "original": original_url,
            "metadata": metadata,
        }

    async def redirect (self, *, short_url: str) -> dict:
        url = self._store.get(short_url)
